import React, { useState, useEffect } from 'react';
import axios from 'axios';

const AlertSystem = () => {
    const [alerts, setAlerts] = useState({ active: [], recent: [] });
    const [loading, setLoading] = useState(false);

    const loadAlerts = async () => {
        try {
            setLoading(true);
            const response = await axios.get('http://localhost:5001/alerts');
            setAlerts(response.data);
        } catch (error) {
            console.error('Load alerts error:', error);
        } finally {
            setLoading(false);
        }
    };

    const resolveAlert = async (alertId) => {
        try {
            await axios.post(`http://localhost:5001/alerts/${alertId}/resolve`, {
                resolved_by: 'user'
            });
            loadAlerts();
        } catch (error) {
            console.error('Resolve alert error:', error);
        }
    };

    const getSeverityColor = (severity) => {
        switch(severity) {
            case 'LOW': return '#28a745';
            case 'MEDIUM': return '#ffc107';
            case 'HIGH': return '#dc3545';
            case 'CRITICAL': return '#721c24';
            default: return '#6c757d';
        }
    };

    useEffect(() => {
        loadAlerts();
        // Refresh every 30 seconds
        const interval = setInterval(loadAlerts, 30000);
        return () => clearInterval(interval);
    }, []);

    return (
        <div className="alert-system-container">
            <h3>Alert System</h3>

            <div className="alert-controls">
                <button onClick={loadAlerts} disabled={loading}>
                    {loading ? 'Loading...' : 'Refresh Alerts'}
                </button>
            </div>

            {alerts.active && alerts.active.length > 0 && (
                <div className="active-alerts">
                    <h4>Active Alerts ({alerts.active.length})</h4>
                    <div className="alerts-list">
                        {alerts.active.map((alert) => (
                            <div key={alert.id} className="alert-item active">
                                <div className="alert-header">
                                    <span 
                                        className="severity-badge"
                                        style={{backgroundColor: getSeverityColor(alert.severity)}}
                                    >
                                        {alert.severity}
                                    </span>
                                    <span className="alert-time">
                                        {new Date(alert.created_at).toLocaleString()}
                                    </span>
                                </div>
                                <div className="alert-title">{alert.title}</div>
                                <div className="alert-message">{alert.message}</div>
                                <div className="alert-source">Source: {alert.source}</div>
                                <button 
                                    className="resolve-btn"
                                    onClick={() => resolveAlert(alert.id)}
                                >
                                    Resolve
                                </button>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {alerts.recent && alerts.recent.length > 0 && (
                <div className="recent-alerts">
                    <h4>Recent Alerts</h4>
                    <div className="alerts-list">
                        {alerts.recent.map((alert) => (
                            <div key={alert.id} className="alert-item">
                                <div className="alert-header">
                                    <span 
                                        className="severity-badge"
                                        style={{backgroundColor: getSeverityColor(alert.severity)}}
                                    >
                                        {alert.severity}
                                    </span>
                                    <span className="alert-time">
                                        {new Date(alert.created_at).toLocaleString()}
                                    </span>
                                </div>
                                <div className="alert-title">{alert.title}</div>
                                <div className="alert-status">Status: {alert.status}</div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            <style jsx>{`
                .alert-system-container {
                    padding: 20px;
                    background: #f5f5f5;
                    border-radius: 8px;
                }
                .alert-controls {
                    margin-bottom: 20px;
                }
                .alert-controls button {
                    padding: 8px 16px;
                    background: #007bff;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    cursor: pointer;
                }
                .alert-controls button:disabled {
                    background: #ccc;
                }
                .active-alerts {
                    margin-bottom: 30px;
                }
                .alerts-list {
                    display: flex;
                    flex-direction: column;
                    gap: 10px;
                }
                .alert-item {
                    padding: 15px;
                    background: white;
                    border-radius: 4px;
                    border-left: 4px solid transparent;
                }
                .alert-item.active {
                    border-left-color: #dc3545;
                }
                .alert-header {
                    display: flex;
                    justify-content: space-between;
                    align-items: center;
                    margin-bottom: 10px;
                }
                .severity-badge {
                    padding: 4px 8px;
                    border-radius: 4px;
                    color: white;
                    font-size: 0.8em;
                    font-weight: bold;
                }
                .alert-time {
                    color: #666;
                    font-size: 0.9em;
                }
                .alert-title {
                    font-weight: bold;
                    margin-bottom: 5px;
                }
                .alert-message {
                    color: #666;
                    margin-bottom: 10px;
                }
                .alert-source {
                    font-size: 0.9em;
                    color: #999;
                    margin-bottom: 10px;
                }
                .alert-status {
                    font-size: 0.9em;
                    color: #28a745;
                }
                .resolve-btn {
                    padding: 4px 8px;
                    background: #28a745;
                    color: white;
                    border: none;
                    border-radius: 4px;
                    cursor: pointer;
                }
            `}</style>
        </div>
    );
};

export default AlertSystem;
